def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        if bins[i] == 0:
            priorities[i] = np.inf
            continue
        ratio = item / bins[i]
        if ratio > 1:
            priorities[i] = ratio ** 2 + np.log(bins[i] + 1)
        elif ratio == 1:
            priorities[i] = 0
        else:
            sum_log = 0
            count = 0
            for j in range(1, 5):
                val = bins[i] / (item + j)
                if val <= 0:
                    priorities[i] += 10
                else:
                    sum_log += np.log(val)
                    count += 1
            if count > 0:
                priorities[i] = -sum_log / count
            else:
                priorities[i] = np.inf
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
